        const tabs = container.querySelectorAll('.tab-content');
        tabs.forEach(tab => tab.classList.remove('active'));
        btnElement.classList.add('active');
        container.querySelector('#' + tabId).classList.add('active');
    }
    function switchWall(wallType, btnElement) {
        const toggleContainer = btnElement.parentElement;
        const btns = toggleContainer.querySelectorAll('.wt-btn');
        btns.forEach(btn => btn.classList.remove('active'));
        btnElement.classList.add('active');
        const wallsContainer = toggleContainer.parentElement;
        const sections = wallsContainer.querySelectorAll('.wall-section');
        sections.forEach(sec => sec.classList.remove('active'));
        wallsContainer.querySelector('#wall-' + wallType).classList.add('active');
